package pl.rezerwacjasal.rezerwacjasal.views; import com.vaadin.flow.component.grid.Grid; import com.vaadin.flow.component.html.*; import com.vaadin.flow.component.orderedlayout.VerticalLayout; import com.vaadin.flow.router.*; import jakarta.annotation.security.RolesAllowed; import pl.rezerwacjasal.rezerwacjasal.model.RoomReservation; import pl.rezerwacjasal.rezerwacjasal.service.RoomReservationService; @Route("rooms/my") @RolesAllowed("CLIENT") public class MyReservationsView extends VerticalLayout { public MyReservationsView(RoomReservationService service) { Grid<RoomReservation> grid=new Grid<>(RoomReservation.class,false); grid.addColumn(r -> r.getRoom().getName()).setHeader("Room"); grid.addColumn(RoomReservation::getStartTime).setHeader("Start"); grid.addColumn(RoomReservation::getEndTime).setHeader("End"); grid.addColumn(RoomReservation::getTotalPrice).setHeader("Price"); grid.setItems(service.getMine()); add(new Anchor("rooms","Rooms"), new H2("My reservations"), grid); } }
